settings._cssCustom:
.ren-accordion .brxe-icon {
  margin-right: 5px;
  transition: transform 0.3s ease;
}

.ren-accordion .brx-open .brxe-icon {
  transform: rotate(90deg);
}

.ren-accordion--style-box > div {
  padding: var(--spacing-sm);
  border: 1px solid #efefef;
  margin-bottom: var(--spacing-xs);
}

.ren-accordion--style-box .accordion-content-wrapper {
  margin-top: var(--spacing-xs);
}

.ren-accordion--style-box-shadow > div {
  box-shadow: 0px 5px 14px 0px rgba(0,0,0,0.08);
	-webkit-box-shadow: 0px 5px 14px 0px rgba(0,0,0,0.08);
	-moz-box-shadow: 0px 5px 14px 0px rgba(0,0,0,0.08);
  padding: var(--spacing-sm);
  border-radius: var(--radius-xs);
  margin-bottom: var(--spacing-xs);
}

.ren-accordion--style-box-shadow .accordion-content-wrapper {
  margin-top: var(--spacing-xs);
}

.ren-grid--layout-01 {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  grid-template-rows: repeat(2, 1fr);
}

.ren-grid--layout-01 :nth-child(1) { grid-area: 1 / 1 / 3 / 2; }
.ren-grid--layout-01 :nth-child(2) { grid-area: 1 / 2 / 2 / 3; }
.ren-grid--layout-01 :nth-child(3) { grid-area: 2 / 2 / 3 / 3; }

settings._cssCustom:mobile_landscape:
.ren-grid--layout-01 {
  grid-template-columns: 1fr;
  grid-template-rows: repeat(3, 1fr);
}

.ren-grid--layout-01 :nth-child(1) { grid-area: auto; }
.ren-grid--layout-01 :nth-child(2) { grid-area: auto; }
.ren-grid--layout-01 :nth-child(3) { grid-area: auto; }

